/*
 * Yalnix Kernel - COMP 421 Lab 2
 * Complete implementation of the Yalnix operating system kernel.
 */

#include <fcntl.h>
#include <unistd.h>
#include <string.h>
#include <stdlib.h>
#include <stdio.h>

#include <comp421/hardware.h>
#include <comp421/yalnix.h>
#include <comp421/loadinfo.h>

/* ================================================================
 *  Constants
 * ================================================================ */
#define CLOCK_QUANTUM    2

/* Process states */
#define PROC_RUNNING     0
#define PROC_READY       1
#define PROC_BLOCKED     2
#define PROC_ZOMBIE      3
#define PROC_DEAD        4

/* Temp mapping page: last VPN of Region 1 */
#define TEMP_VPN         (PAGE_TABLE_LEN - 1)
#define TEMP_VADDR       (VMEM_1_BASE + TEMP_VPN * PAGESIZE)

/* ================================================================
 *  Data Structures
 * ================================================================ */
typedef struct pcb {
    int pid;
    int state;
    SavedContext ctx;
    struct pte *pt;              /* Region 0 page table (virtual addr in R1) */
    unsigned long pt_phys;       /* Physical addr of Region 0 page table */
    int brk_page;                /* First VPN above user heap in R0 */
    int stack_base;              /* Lowest allocated user stack VPN in R0 */
    int exit_status;
    int clock_ticks;             /* Ticks running since last switch-in */
    int delay_remaining;         /* Remaining Delay ticks */
    int is_waiting;              /* Blocked in Wait */
    int wait_child_pid;          /* Result from child exit */
    int wait_child_status;
    struct pcb *parent;
    struct pcb *next;            /* Ready / delay / wait / tty queue link */
    struct pcb *children;        /* Head of children list */
    struct pcb *sibling;         /* Next child in parent's children list */
    struct pcb *zombie_children; /* Head of zombie list */
    struct pcb *zombie_next;     /* Link in parent's zombie list */
} pcb_t;

typedef struct tty_line {
    char data[TERMINAL_MAX_LINE];
    int len;
    struct tty_line *next;
} tty_line_t;

/* ================================================================
 *  Global Variables
 * ================================================================ */

/* Page tables */
static struct pte r1_pt[PAGE_TABLE_LEN];       /* Region 1 (kernel) */
static struct pte boot_r0_pt[PAGE_TABLE_LEN];  /* Initial Region 0 */

/* VM state */
static int vm_on = 0;
static void *kernel_brk_addr;
static int kernel_brk_page;   /* Global VPN of kernel break */

/* Frame management */
static int *frame_free;        /* 1 = free, 0 = used */
static int total_frames;
static int num_free;

/* Process management */
static pcb_t *cur_proc = NULL;
static pcb_t *idle_proc = NULL;
static int next_pid = 0;
static int num_procs = 0;      /* Living processes (not idle) */

/* Ready queue */
static pcb_t *rq_head = NULL;
static pcb_t *rq_tail = NULL;

/* Delay queue */
static pcb_t *delay_q = NULL;

/* Reap list (dead orphans awaiting kernel stack cleanup) */
static pcb_t *reap_list = NULL;

/* TTY state */
static tty_line_t *tty_in_head[NUM_TERMINALS];
static tty_line_t *tty_in_tail[NUM_TERMINALS];
static pcb_t *tty_rd_wait[NUM_TERMINALS];       /* Blocked reader */
static pcb_t *tty_wr_active[NUM_TERMINALS];     /* Currently transmitting */
static pcb_t *tty_wr_head[NUM_TERMINALS];       /* Write wait queue */
static pcb_t *tty_wr_tail[NUM_TERMINALS];
static char tty_kbuf[NUM_TERMINALS][TERMINAL_MAX_LINE]; /* Kernel write bufs */

/* Interrupt vector table */
static void (*ivt[TRAP_VECTOR_SIZE])(ExceptionInfo *);

/* Page table pool: allocated at high Region 1 VPNs, growing down */
static int pt_pool_next_vpn;  /* Next VPN to use (decrements) */

/* ================================================================
 *  Forward Declarations
 * ================================================================ */
static void trap_kernel(ExceptionInfo *info);
static void trap_clock(ExceptionInfo *info);
static void trap_illegal(ExceptionInfo *info);
static void trap_memory(ExceptionInfo *info);
static void trap_math(ExceptionInfo *info);
static void trap_tty_recv(ExceptionInfo *info);
static void trap_tty_xmit(ExceptionInfo *info);

static int kern_fork(ExceptionInfo *info);
static int kern_exec(char *name, char **argv, ExceptionInfo *info);
static void kern_exit(int status, ExceptionInfo *info);
static int kern_wait(int *status_ptr, ExceptionInfo *info);
static int kern_brk(void *addr);
static int kern_delay(int ticks, ExceptionInfo *info);
static int kern_ttyread(int tty_id, void *buf, int len, ExceptionInfo *info);
static int kern_ttywrite(int tty_id, void *buf, int len, ExceptionInfo *info);
static int load_program(char *name, char **args, ExceptionInfo *info, pcb_t *proc);
static void do_idle(void);

/* ================================================================
 *  Frame Management
 * ================================================================ */
static int alloc_frame(void) {
    int i;
    for (i = 0; i < total_frames; i++) {
        if (frame_free[i]) {
            frame_free[i] = 0;
            num_free--;
            return i;
        }
    }
    return -1;
}

static void free_frame(int pfn) {
    if (pfn >= 0 && pfn < total_frames && !frame_free[pfn]) {
        frame_free[pfn] = 1;
        num_free++;
    }
}

/* ================================================================
 *  Queue Helpers
 * ================================================================ */
static void enqueue_ready(pcb_t *p) {
    p->state = PROC_READY;
    p->next = NULL;
    if (!rq_tail) {
        rq_head = rq_tail = p;
    } else {
        rq_tail->next = p;
        rq_tail = p;
    }
}

static pcb_t *dequeue_ready(void) {
    pcb_t *p = rq_head;
    if (p) {
        rq_head = p->next;
        if (!rq_head) rq_tail = NULL;
        p->next = NULL;
    }
    return p;
}

/* ================================================================
 *  Virtual-to-Physical Translation
 * ================================================================ */
static unsigned long v2p(void *vaddr) {
    unsigned long a = (unsigned long)vaddr;
    int vpn, offset;
    if (a >= VMEM_1_BASE && a < VMEM_1_LIMIT) {
        vpn = (a - VMEM_1_BASE) >> PAGESHIFT;
        offset = a & PAGEOFFSET;
        return ((unsigned long)r1_pt[vpn].pfn << PAGESHIFT) | offset;
    }
    return a; /* Before VM or for Region 0 identity */
}

/* ================================================================
 *  Page Table Allocation (from physical frames, mapped in R1)
 * ================================================================ */
static struct pte *alloc_pt(unsigned long *phys_out) {
    int pfn = alloc_frame();
    if (pfn < 0) return NULL;

    int vpn = pt_pool_next_vpn--;
    if (vpn <= 0) {
        free_frame(pfn);
        pt_pool_next_vpn++;
        return NULL;
    }

    r1_pt[vpn].valid = 1;
    r1_pt[vpn].kprot = PROT_READ | PROT_WRITE;
    r1_pt[vpn].uprot = PROT_NONE;
    r1_pt[vpn].pfn = pfn;
    WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)(VMEM_1_BASE + vpn * PAGESIZE));

    struct pte *pt = (struct pte *)(VMEM_1_BASE + vpn * PAGESIZE);
    memset(pt, 0, PAGE_TABLE_SIZE);
    *phys_out = (unsigned long)pfn << PAGESHIFT;
    return pt;
}

static void free_pt(struct pte *pt) {
    unsigned long va = (unsigned long)pt;
    int vpn = (va - VMEM_1_BASE) >> PAGESHIFT;
    free_frame(r1_pt[vpn].pfn);
    r1_pt[vpn].valid = 0;
    WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)va);
}

/* ================================================================
 *  Reap dead (orphan) processes - free kernel stack + PCB
 * ================================================================ */
static void reap_dead(void) {
    while (reap_list) {
        pcb_t *d = reap_list;
        reap_list = d->next;
        int i;
        int ks_base = KERNEL_STACK_BASE >> PAGESHIFT;
        for (i = 0; i < KERNEL_STACK_PAGES; i++) {
            if (d->pt[ks_base + i].valid)
                free_frame(d->pt[ks_base + i].pfn);
        }
        free_pt(d->pt);
        free(d);
    }
}

/* Free a zombie's kernel stack + PCB (called when parent collects) */
static void free_zombie(pcb_t *z) {
    int i, ks_base = KERNEL_STACK_BASE >> PAGESHIFT;
    for (i = 0; i < KERNEL_STACK_PAGES; i++) {
        if (z->pt[ks_base + i].valid)
            free_frame(z->pt[ks_base + i].pfn);
    }
    free_pt(z->pt);
    free(z);
}

/* ================================================================
 *  Validation Helpers
 * ================================================================ */
static int check_buf(void *ptr, int len, int need_write) {
    unsigned long addr = (unsigned long)ptr;
    unsigned long end;
    unsigned long p;

    if (len <= 0) return (len == 0) ? 1 : 0;
    end = addr + len - 1;
    if (addr < MEM_INVALID_SIZE || end >= KERNEL_STACK_BASE) return 0;

    for (p = addr >> PAGESHIFT; p <= (end >> PAGESHIFT); p++) {
        if (p >= PAGE_TABLE_LEN) return 0;
        if (!cur_proc->pt[p].valid) return 0;
        if (!(cur_proc->pt[p].uprot & PROT_READ)) return 0;
        if (need_write && !(cur_proc->pt[p].uprot & PROT_WRITE)) return 0;
    }
    return 1;
}

static int check_str(char *str) {
    unsigned long addr = (unsigned long)str;
    if (addr < MEM_INVALID_SIZE) return 0;
    while (addr < KERNEL_STACK_BASE) {
        unsigned long page = addr >> PAGESHIFT;
        if (page >= PAGE_TABLE_LEN) return 0;
        if (!cur_proc->pt[page].valid) return 0;
        if (!(cur_proc->pt[page].uprot & PROT_READ)) return 0;
        if (*(char *)addr == '\0') return 1;
        addr++;
    }
    return 0;
}

/* ================================================================
 *  Context Switch Functions
 * ================================================================ */

/*
 * Normal context switch between two processes.
 */
static SavedContext *switch_func(SavedContext *ctxp, void *p1, void *p2) {
    pcb_t *old_p = (pcb_t *)p1;
    pcb_t *new_p = (pcb_t *)p2;

    memcpy(&old_p->ctx, ctxp, sizeof(SavedContext));

    WriteRegister(REG_PTR0, (RCS421RegVal)new_p->pt_phys);
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);

    cur_proc = new_p;
    return &new_p->ctx;
}

/*
 * Copy kernel stack to a new process (used in KernelStart for idle).
 * Does NOT actually switch—returns same context.
 */
static SavedContext *copy_switch(SavedContext *ctxp, void *p1, void *p2) {
    pcb_t *target = (pcb_t *)p1;
    (void)p2;

    memcpy(&target->ctx, ctxp, sizeof(SavedContext));

    int ks_base = KERNEL_STACK_BASE >> PAGESHIFT;
    int i;
    for (i = 0; i < KERNEL_STACK_PAGES; i++) {
        int dst_pfn = target->pt[ks_base + i].pfn;
        r1_pt[TEMP_VPN].valid = 1;
        r1_pt[TEMP_VPN].kprot = PROT_READ | PROT_WRITE;
        r1_pt[TEMP_VPN].uprot = PROT_NONE;
        r1_pt[TEMP_VPN].pfn = dst_pfn;
        WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)TEMP_VADDR);
        memcpy((void *)TEMP_VADDR,
               (void *)((unsigned long)(ks_base + i) << PAGESHIFT),
               PAGESIZE);
    }
    r1_pt[TEMP_VPN].valid = 0;
    WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)TEMP_VADDR);

    return ctxp;
}

/*
 * Fork: copy kernel stack from parent to child.
 * Returns parent context (child saved separately).
 */
static SavedContext *fork_switch(SavedContext *ctxp, void *p1, void *p2) {
    pcb_t *parent = (pcb_t *)p1;
    pcb_t *child  = (pcb_t *)p2;

    memcpy(&parent->ctx, ctxp, sizeof(SavedContext));
    memcpy(&child->ctx, ctxp, sizeof(SavedContext));

    int ks_base = KERNEL_STACK_BASE >> PAGESHIFT;
    int i;
    for (i = 0; i < KERNEL_STACK_PAGES; i++) {
        int dst_pfn = child->pt[ks_base + i].pfn;
        r1_pt[TEMP_VPN].valid = 1;
        r1_pt[TEMP_VPN].kprot = PROT_READ | PROT_WRITE;
        r1_pt[TEMP_VPN].uprot = PROT_NONE;
        r1_pt[TEMP_VPN].pfn = dst_pfn;
        WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)TEMP_VADDR);
        memcpy((void *)TEMP_VADDR,
               (void *)((unsigned long)(ks_base + i) << PAGESHIFT),
               PAGESIZE);
    }
    r1_pt[TEMP_VPN].valid = 0;
    WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)TEMP_VADDR);

    return ctxp; /* Resume as parent */
}

/* ================================================================
 *  Scheduling
 * ================================================================ */
static void schedule(ExceptionInfo *info) {
    (void)info;
    reap_dead();

    pcb_t *next = dequeue_ready();
    if (!next) next = idle_proc;
    if (next == cur_proc) return;

    pcb_t *old = cur_proc;
    next->state = PROC_RUNNING;
    next->clock_ticks = 0;

    ContextSwitch(switch_func, &old->ctx, old, next);
    /* On return, cur_proc has been set by switch_func */
    reap_dead();
}

/* ================================================================
 *  Process Termination
 * ================================================================ */
static void remove_child(pcb_t *parent, pcb_t *child) {
    pcb_t **pp = &parent->children;
    while (*pp && *pp != child) pp = &(*pp)->sibling;
    if (*pp == child) *pp = child->sibling;
    child->sibling = NULL;
}

static void terminate(pcb_t *proc, int status, ExceptionInfo *info) {
    TracePrintf(1, "Terminate pid %d status %d\n", proc->pid, status);
    int i;

    /* Free user pages (not kernel stack) */
    int ks_base = KERNEL_STACK_BASE >> PAGESHIFT;
    for (i = 0; i < ks_base; i++) {
        if (proc->pt[i].valid) {
            free_frame(proc->pt[i].pfn);
            proc->pt[i].valid = 0;
        }
    }

    /* Orphan all children */
    pcb_t *ch = proc->children;
    while (ch) {
        pcb_t *nxt = ch->sibling;
        ch->parent = NULL;
        ch->sibling = NULL;
        ch = nxt;
    }
    proc->children = NULL;

    /* Free zombie children (they'll never be collected) */
    pcb_t *z = proc->zombie_children;
    while (z) {
        pcb_t *nxt = z->zombie_next;
        free_zombie(z);
        z = nxt;
    }
    proc->zombie_children = NULL;

    /* Notify parent */
    if (proc->parent) {
        pcb_t *par = proc->parent;
        remove_child(par, proc);

        if (par->is_waiting) {
            /* Wake parent */
            par->wait_child_pid = proc->pid;
            par->wait_child_status = status;
            par->is_waiting = 0;
            enqueue_ready(par);
            /* Defer cleanup of proc */
            proc->state = PROC_DEAD;
            proc->next = reap_list;
            reap_list = proc;
        } else {
            /* Become zombie */
            proc->state = PROC_ZOMBIE;
            proc->exit_status = status;
            proc->zombie_next = par->zombie_children;
            par->zombie_children = proc;
        }
    } else {
        /* Orphan - defer cleanup */
        proc->state = PROC_DEAD;
        proc->next = reap_list;
        reap_list = proc;
    }

    num_procs--;
    if (num_procs <= 0) {
        TracePrintf(0, "All user processes exited. Halting.\n");
        Halt();
    }

    /* Must switch away from this process */
    pcb_t *next = dequeue_ready();
    if (!next) next = idle_proc;

    pcb_t *old = cur_proc;
    next->state = PROC_RUNNING;
    next->clock_ticks = 0;
    ContextSwitch(switch_func, &old->ctx, old, next);
    reap_dead();
}

/* ================================================================
 *  Idle Process
 * ================================================================ */
static void do_idle(void) {
    while (1) {
        Pause();
    }
}

/* ================================================================
 *  Trap Handlers
 * ================================================================ */
static void trap_kernel(ExceptionInfo *info) {
    int code = info->code;
    int result;

    switch (code) {
    case YALNIX_FORK:
        result = kern_fork(info);
        info->regs[0] = result;
        break;
    case YALNIX_EXEC:
        result = kern_exec((char *)info->regs[1], (char **)info->regs[2], info);
        info->regs[0] = result;
        break;
    case YALNIX_EXIT:
        kern_exit((int)info->regs[1], info);
        /* Should not return for the exiting process */
        break;
    case YALNIX_WAIT:
        result = kern_wait((int *)info->regs[1], info);
        info->regs[0] = result;
        break;
    case YALNIX_GETPID:
        info->regs[0] = cur_proc->pid;
        break;
    case YALNIX_BRK:
        result = kern_brk((void *)info->regs[1]);
        info->regs[0] = result;
        break;
    case YALNIX_DELAY:
        result = kern_delay((int)info->regs[1], info);
        info->regs[0] = result;
        break;
    case YALNIX_TTY_READ:
        result = kern_ttyread((int)info->regs[1], (void *)info->regs[2],
                              (int)info->regs[3], info);
        info->regs[0] = result;
        break;
    case YALNIX_TTY_WRITE:
        result = kern_ttywrite((int)info->regs[1], (void *)info->regs[2],
                               (int)info->regs[3], info);
        info->regs[0] = result;
        break;
    default:
        TracePrintf(0, "Unknown syscall %d from pid %d\n", code, cur_proc->pid);
        info->regs[0] = ERROR;
        break;
    }
}

static void trap_clock(ExceptionInfo *info) {
    /* Decrement delay counters */
    pcb_t **pp = &delay_q;
    while (*pp) {
        (*pp)->delay_remaining--;
        if ((*pp)->delay_remaining <= 0) {
            pcb_t *wake = *pp;
            *pp = wake->next;
            wake->next = NULL;
            enqueue_ready(wake);
        } else {
            pp = &(*pp)->next;
        }
    }

    /* Round-robin scheduling */
    if (cur_proc != idle_proc) {
        cur_proc->clock_ticks++;
        if (cur_proc->clock_ticks >= CLOCK_QUANTUM && rq_head) {
            enqueue_ready(cur_proc);
            schedule(info);
        }
    } else {
        /* Idle: switch to any ready process */
        if (rq_head) {
            schedule(info);
        }
    }
}

static void trap_illegal(ExceptionInfo *info) {
    TracePrintf(0, "TRAP_ILLEGAL: pid %d, code %d, pc %p\n",
                cur_proc->pid, info->code, info->pc);
    if (cur_proc == idle_proc) { Halt(); }
    terminate(cur_proc, ERROR, info);
}

static void trap_memory(ExceptionInfo *info) {
    unsigned long addr = (unsigned long)info->addr;
    int fault_vpn = addr >> PAGESHIFT;
    int ks_base = KERNEL_STACK_BASE >> PAGESHIFT;

    /* Check if this is a stack growth request */
    if (addr >= MEM_INVALID_SIZE && addr < (unsigned long)USER_STACK_LIMIT &&
        fault_vpn >= cur_proc->brk_page + 1 &&  /* Red zone */
        fault_vpn < (USER_STACK_LIMIT >> PAGESHIFT)) {

        /* Grow stack down to fault_vpn */
        int i;
        for (i = fault_vpn; i < cur_proc->stack_base; i++) {
            if (cur_proc->pt[i].valid) continue;
            int pfn = alloc_frame();
            if (pfn < 0) goto kill;
            cur_proc->pt[i].valid = 1;
            cur_proc->pt[i].kprot = PROT_READ | PROT_WRITE;
            cur_proc->pt[i].uprot = PROT_READ | PROT_WRITE;
            cur_proc->pt[i].pfn = pfn;
        }
        cur_proc->stack_base = fault_vpn;
        WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
        return;
    }

kill:
    TracePrintf(0, "TRAP_MEMORY: pid %d, addr %p, code %d\n",
                cur_proc->pid, info->addr, info->code);
    if (cur_proc == idle_proc) { Halt(); }
    terminate(cur_proc, ERROR, info);
}

static void trap_math(ExceptionInfo *info) {
    TracePrintf(0, "TRAP_MATH: pid %d, code %d\n", cur_proc->pid, info->code);
    if (cur_proc == idle_proc) { Halt(); }
    terminate(cur_proc, ERROR, info);
}

static void trap_tty_recv(ExceptionInfo *info) {
    int tty = info->code;
    if (tty < 0 || tty >= NUM_TERMINALS) return;

    /* Read from hardware into a new buffer */
    tty_line_t *line = (tty_line_t *)malloc(sizeof(tty_line_t));
    if (!line) return;
    line->len = TtyReceive(tty, line->data, TERMINAL_MAX_LINE);
    line->next = NULL;

    /* Append to input queue */
    if (!tty_in_tail[tty]) {
        tty_in_head[tty] = tty_in_tail[tty] = line;
    } else {
        tty_in_tail[tty]->next = line;
        tty_in_tail[tty] = line;
    }

    /* Wake blocked reader if any */
    if (tty_rd_wait[tty]) {
        pcb_t *reader = tty_rd_wait[tty];
        tty_rd_wait[tty] = reader->next;
        reader->next = NULL;
        enqueue_ready(reader);
    }
}

static void trap_tty_xmit(ExceptionInfo *info) {
    int tty = info->code;
    if (tty < 0 || tty >= NUM_TERMINALS) return;

    /* Current transmit is done; unblock the writer */
    pcb_t *writer = tty_wr_active[tty];
    tty_wr_active[tty] = NULL;
    if (writer) {
        writer->tty_wr_active[tty] = NULL; /* Not a real field, see below */
        enqueue_ready(writer);
    }

    /* Start next pending write if any */
    if (tty_wr_head[tty]) {
        pcb_t *nw = tty_wr_head[tty];
        tty_wr_head[tty] = nw->next;
        if (!tty_wr_head[tty]) tty_wr_tail[tty] = NULL;
        nw->next = NULL;
        tty_wr_active[tty] = nw;
        /* Copy from saved data and transmit */
        /* The data was already copied to tty_kbuf when TtyWrite was called */
        TtyTransmit(tty, tty_kbuf[tty], nw->exit_status); /* Reusing exit_status for len */
    }
}

/* ================================================================
 *  Kernel Call Implementations
 * ================================================================ */

static int kern_fork(ExceptionInfo *info) {
    int i;
    int ks_base = KERNEL_STACK_BASE >> PAGESHIFT;

    /* Count how many pages the child needs */
    int pages_needed = KERNEL_STACK_PAGES;
    for (i = 0; i < ks_base; i++) {
        if (cur_proc->pt[i].valid) pages_needed++;
    }
    if (pages_needed > num_free) return ERROR;

    /* Allocate child PCB */
    pcb_t *child = (pcb_t *)malloc(sizeof(pcb_t));
    if (!child) return ERROR;
    memset(child, 0, sizeof(pcb_t));
    child->pid = next_pid++;
    child->state = PROC_READY;
    child->brk_page = cur_proc->brk_page;
    child->stack_base = cur_proc->stack_base;
    child->parent = cur_proc;

    /* Allocate page table */
    unsigned long child_pt_phys;
    child->pt = alloc_pt(&child_pt_phys);
    if (!child->pt) {
        free(child);
        return ERROR;
    }
    child->pt_phys = child_pt_phys;

    /* Allocate kernel stack pages for child */
    for (i = 0; i < KERNEL_STACK_PAGES; i++) {
        int pfn = alloc_frame();
        if (pfn < 0) {
            /* Cleanup */
            int j;
            for (j = 0; j < i; j++)
                free_frame(child->pt[ks_base + j].pfn);
            free_pt(child->pt);
            free(child);
            return ERROR;
        }
        child->pt[ks_base + i].valid = 1;
        child->pt[ks_base + i].kprot = PROT_READ | PROT_WRITE;
        child->pt[ks_base + i].uprot = PROT_NONE;
        child->pt[ks_base + i].pfn = pfn;
    }

    /* Copy user pages from parent to child */
    for (i = 0; i < ks_base; i++) {
        if (!cur_proc->pt[i].valid) continue;
        int pfn = alloc_frame();
        if (pfn < 0) {
            /* Cleanup: free all child pages allocated so far */
            int j;
            for (j = 0; j < ks_base; j++) {
                if (child->pt[j].valid) free_frame(child->pt[j].pfn);
            }
            for (j = 0; j < KERNEL_STACK_PAGES; j++)
                free_frame(child->pt[ks_base + j].pfn);
            free_pt(child->pt);
            free(child);
            return ERROR;
        }
        child->pt[i] = cur_proc->pt[i];
        child->pt[i].pfn = pfn;

        /* Copy page via temp mapping */
        r1_pt[TEMP_VPN].valid = 1;
        r1_pt[TEMP_VPN].kprot = PROT_READ | PROT_WRITE;
        r1_pt[TEMP_VPN].uprot = PROT_NONE;
        r1_pt[TEMP_VPN].pfn = pfn;
        WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)TEMP_VADDR);
        memcpy((void *)TEMP_VADDR, (void *)((unsigned long)i << PAGESHIFT), PAGESIZE);
    }
    r1_pt[TEMP_VPN].valid = 0;
    WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)TEMP_VADDR);

    /* Link child to parent */
    child->sibling = cur_proc->children;
    cur_proc->children = child;
    num_procs++;

    /* Copy kernel stack and create SavedContext for child */
    ContextSwitch(fork_switch, &cur_proc->ctx, cur_proc, child);

    /* Both parent and child resume here */
    if (cur_proc->pid == child->pid) {
        /* We are the child */
        return 0;
    }

    /* We are the parent */
    enqueue_ready(child);
    return child->pid;
}

static int kern_exec(char *name, char **argv, ExceptionInfo *info) {
    if (!check_str(name)) return ERROR;

    /* Validate argv array */
    unsigned long argv_addr = (unsigned long)argv;
    if (argv_addr < MEM_INVALID_SIZE) return ERROR;
    int argc = 0;
    while (1) {
        if (!check_buf(&argv[argc], sizeof(char *), 0)) return ERROR;
        if (argv[argc] == NULL) break;
        if (!check_str(argv[argc])) return ERROR;
        argc++;
    }

    int rc = load_program(name, argv, info, cur_proc);
    if (rc < 0) {
        if (rc == -2) {
            /* Process is no longer runnable */
            terminate(cur_proc, ERROR, info);
            return ERROR; /* Not reached */
        }
        return ERROR;
    }
    /* On success, load_program sets up info for the new program.
     * When trap handler returns, the new program starts. */
    return 0; /* Not actually used - new program starts fresh */
}

static void kern_exit(int status, ExceptionInfo *info) {
    if (cur_proc == idle_proc) {
        TracePrintf(0, "Idle tried to exit. Halting.\n");
        Halt();
    }
    terminate(cur_proc, status, info);
}

static int kern_wait(int *status_ptr, ExceptionInfo *info) {
    /* Validate status_ptr */
    if (!check_buf(status_ptr, sizeof(int), 1)) return ERROR;

    /* Check for zombie children */
    if (cur_proc->zombie_children) {
        pcb_t *z = cur_proc->zombie_children;
        cur_proc->zombie_children = z->zombie_next;
        int pid = z->pid;
        *status_ptr = z->exit_status;
        free_zombie(z);
        return pid;
    }

    /* Any living children? */
    if (!cur_proc->children) return ERROR;

    /* Block until a child exits */
    cur_proc->state = PROC_BLOCKED;
    cur_proc->is_waiting = 1;
    schedule(info);

    /* Woken up by child exit */
    *status_ptr = cur_proc->wait_child_status;
    return cur_proc->wait_child_pid;
}

static int kern_brk(void *addr) {
    unsigned long new_brk = (unsigned long)UP_TO_PAGE(addr);
    int new_brk_page = new_brk >> PAGESHIFT;
    int i;

    if (new_brk_page < MEM_INVALID_PAGES) return ERROR;
    /* Must leave red zone between heap and stack */
    if (new_brk_page >= cur_proc->stack_base) return ERROR;

    if (new_brk_page > cur_proc->brk_page) {
        /* Growing */
        int needed = new_brk_page - cur_proc->brk_page;
        if (needed > num_free) return ERROR;
        for (i = cur_proc->brk_page; i < new_brk_page; i++) {
            int pfn = alloc_frame();
            if (pfn < 0) return ERROR;
            cur_proc->pt[i].valid = 1;
            cur_proc->pt[i].kprot = PROT_READ | PROT_WRITE;
            cur_proc->pt[i].uprot = PROT_READ | PROT_WRITE;
            cur_proc->pt[i].pfn = pfn;
        }
    } else if (new_brk_page < cur_proc->brk_page) {
        /* Shrinking */
        for (i = new_brk_page; i < cur_proc->brk_page; i++) {
            if (cur_proc->pt[i].valid) {
                free_frame(cur_proc->pt[i].pfn);
                cur_proc->pt[i].valid = 0;
            }
        }
    }
    cur_proc->brk_page = new_brk_page;
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
    return 0;
}

static int kern_delay(int ticks, ExceptionInfo *info) {
    if (ticks < 0) return ERROR;
    if (ticks == 0) return 0;

    cur_proc->delay_remaining = ticks;
    cur_proc->state = PROC_BLOCKED;
    cur_proc->next = delay_q;
    delay_q = cur_proc;

    schedule(info);
    return 0;
}

static int kern_ttyread(int tty_id, void *buf, int len, ExceptionInfo *info) {
    if (tty_id < 0 || tty_id >= NUM_TERMINALS) return ERROR;
    if (len < 0) return ERROR;
    if (len == 0) return 0;
    if (!check_buf(buf, len, 1)) return ERROR;

    /* Wait for input if none available */
    while (!tty_in_head[tty_id]) {
        cur_proc->state = PROC_BLOCKED;
        cur_proc->next = tty_rd_wait[tty_id];
        tty_rd_wait[tty_id] = cur_proc;
        schedule(info);
    }

    /* Copy from input buffer */
    tty_line_t *line = tty_in_head[tty_id];
    int to_copy = (len < line->len) ? len : line->len;
    memcpy(buf, line->data, to_copy);

    if (to_copy < line->len) {
        /* Partial read: shift remaining data */
        memmove(line->data, line->data + to_copy, line->len - to_copy);
        line->len -= to_copy;
    } else {
        /* Consumed entire line */
        tty_in_head[tty_id] = line->next;
        if (!tty_in_head[tty_id]) tty_in_tail[tty_id] = NULL;
        free(line);
    }
    return to_copy;
}

static int kern_ttywrite(int tty_id, void *buf, int len, ExceptionInfo *info) {
    if (tty_id < 0 || tty_id >= NUM_TERMINALS) return ERROR;
    if (len < 0 || len > TERMINAL_MAX_LINE) return ERROR;
    if (len == 0) return 0;
    if (!check_buf(buf, len, 0)) return ERROR;

    /* Copy user data to kernel buffer */
    memcpy(tty_kbuf[tty_id], buf, len);
    int orig_len = len;

    if (!tty_wr_active[tty_id]) {
        /* Terminal is free; start transmitting */
        tty_wr_active[tty_id] = cur_proc;
        cur_proc->exit_status = len; /* Stash len for transmit handler */
        TtyTransmit(tty_id, tty_kbuf[tty_id], len);
    } else {
        /* Queue this write */
        cur_proc->exit_status = len;
        cur_proc->next = NULL;
        if (!tty_wr_tail[tty_id]) {
            tty_wr_head[tty_id] = tty_wr_tail[tty_id] = cur_proc;
        } else {
            tty_wr_tail[tty_id]->next = cur_proc;
            tty_wr_tail[tty_id] = cur_proc;
        }
    }

    /* Block until transmit completes */
    cur_proc->state = PROC_BLOCKED;
    schedule(info);

    return orig_len;
}

/* ================================================================
 *  LoadProgram (adapted from load.template)
 * ================================================================ */
static int
load_program(char *name, char **args, ExceptionInfo *info, pcb_t *proc)
{
    int fd;
    int status;
    struct loadinfo li;
    char *cp;
    char *cp2;
    char **cpp;
    char *argbuf;
    int i;
    unsigned long argcount;
    int size;
    int text_npg;
    int data_bss_npg;
    int stack_npg;

    TracePrintf(1, "LoadProgram '%s', args %p\n", name, args);

    if ((fd = open(name, O_RDONLY)) < 0) {
        TracePrintf(0, "LoadProgram: can't open file '%s'\n", name);
        return (-1);
    }

    status = LoadInfo(fd, &li);
    TracePrintf(1, "LoadProgram: LoadInfo status %d\n", status);
    switch (status) {
    case LI_SUCCESS:
        break;
    case LI_FORMAT_ERROR:
        TracePrintf(0, "LoadProgram: '%s' not in Yalnix format\n", name);
        close(fd);
        return (-1);
    case LI_OTHER_ERROR:
        TracePrintf(0, "LoadProgram: '%s' other error\n", name);
        close(fd);
        return (-1);
    default:
        TracePrintf(0, "LoadProgram: '%s' unknown error\n", name);
        close(fd);
        return (-1);
    }
    TracePrintf(1, "text_size 0x%lx, data_size 0x%lx, bss_size 0x%lx\n",
                li.text_size, li.data_size, li.bss_size);
    TracePrintf(1, "entry 0x%lx\n", li.entry);

    /*
     *  Figure out how many bytes for arguments on new stack.
     */
    size = 0;
    for (i = 0; args[i] != NULL; i++) {
        size += strlen(args[i]) + 1;
    }
    argcount = i;
    TracePrintf(1, "LoadProgram: size %d, argcount %d\n", size, (int)argcount);

    /*
     *  Save arguments in Region 1 buffer.
     */
    cp = argbuf = (char *)malloc(size);
    if (!argbuf) { close(fd); return (-1); }
    for (i = 0; args[i] != NULL; i++) {
        strcpy(cp, args[i]);
        cp += strlen(cp) + 1;
    }

    /*
     *  Compute stack layout.
     */
    cp = ((char *)USER_STACK_LIMIT) - size;
    cpp = (char **)((unsigned long)cp & (-1 << 4));   /* align cpp */
    cpp = (char **)((unsigned long)cpp - ((argcount + 4) * sizeof(void *)));

    text_npg = li.text_size >> PAGESHIFT;
    data_bss_npg = UP_TO_PAGE(li.data_size + li.bss_size) >> PAGESHIFT;
    stack_npg = (USER_STACK_LIMIT - DOWN_TO_PAGE(cpp)) >> PAGESHIFT;

    TracePrintf(1, "LoadProgram: text_npg %d, data_bss_npg %d, stack_npg %d\n",
                text_npg, data_bss_npg, stack_npg);

    /*
     *  Check virtual memory size.
     */
    if (MEM_INVALID_PAGES + text_npg + data_bss_npg + 1 + stack_npg +
        1 + KERNEL_STACK_PAGES > PAGE_TABLE_LEN) {
        TracePrintf(0, "LoadProgram: '%s' too large for VIRTUAL memory\n", name);
        free(argbuf);
        close(fd);
        return (-1);
    }

    /*
     *  Check physical memory (accounting for pages that will be freed).
     */
    {
        int pages_needed = text_npg + data_bss_npg + stack_npg;
        int pages_to_free = 0;
        int ks_base_vpn = KERNEL_STACK_BASE >> PAGESHIFT;
        for (i = 0; i < ks_base_vpn; i++) {
            if (proc->pt[i].valid) pages_to_free++;
        }
        if (pages_needed - pages_to_free > num_free) {
            TracePrintf(0, "LoadProgram: '%s' too large for PHYSICAL memory\n", name);
            free(argbuf);
            close(fd);
            return (-1);
        }
    }

    /* Initialize sp */
    info->sp = (void *)cpp;

    /*
     *  Free old Region 0 pages (except kernel stack).
     */
    {
        int ks_base_vpn = KERNEL_STACK_BASE >> PAGESHIFT;
        for (i = 0; i < ks_base_vpn; i++) {
            if (proc->pt[i].valid) {
                free_frame(proc->pt[i].pfn);
                proc->pt[i].valid = 0;
            }
        }
    }

    /*
     *  Set up text, data+bss, stack pages.
     */
    {
        int vpn = MEM_INVALID_PAGES;

        /* Text pages */
        for (i = 0; i < text_npg; i++) {
            int pfn = alloc_frame();
            proc->pt[vpn].valid = 1;
            proc->pt[vpn].kprot = PROT_READ | PROT_WRITE;
            proc->pt[vpn].uprot = PROT_READ | PROT_EXEC;
            proc->pt[vpn].pfn = pfn;
            vpn++;
        }

        /* Data + BSS pages */
        for (i = 0; i < data_bss_npg; i++) {
            int pfn = alloc_frame();
            proc->pt[vpn].valid = 1;
            proc->pt[vpn].kprot = PROT_READ | PROT_WRITE;
            proc->pt[vpn].uprot = PROT_READ | PROT_WRITE;
            proc->pt[vpn].pfn = pfn;
            vpn++;
        }

        /* Update brk for this process */
        proc->brk_page = vpn;

        /* Stack pages (at top of Region 0 user area) */
        int stack_top_vpn = (USER_STACK_LIMIT >> PAGESHIFT) - 1;
        for (i = 0; i < stack_npg; i++) {
            int sv = stack_top_vpn - stack_npg + 1 + i;
            int pfn = alloc_frame();
            proc->pt[sv].valid = 1;
            proc->pt[sv].kprot = PROT_READ | PROT_WRITE;
            proc->pt[sv].uprot = PROT_READ | PROT_WRITE;
            proc->pt[sv].pfn = pfn;
        }
        proc->stack_base = stack_top_vpn - stack_npg + 1;
    }

    /* Flush TLB for Region 0 */
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);

    /*
     *  Read text and data from file.
     */
    if (read(fd, (void *)MEM_INVALID_SIZE, li.text_size + li.data_size)
        != (ssize_t)(li.text_size + li.data_size)) {
        TracePrintf(0, "LoadProgram: couldn't read for '%s'\n", name);
        free(argbuf);
        close(fd);
        return (-2);
    }

    close(fd);

    /*
     *  Set text pages to read/exec (was read/write for loading).
     */
    {
        int vpn = MEM_INVALID_PAGES;
        for (i = 0; i < text_npg; i++) {
            proc->pt[vpn + i].kprot = PROT_READ | PROT_EXEC;
        }
    }
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);

    /*
     *  Zero out BSS.
     */
    memset((void *)(MEM_INVALID_SIZE + li.text_size + li.data_size),
           '\0', li.bss_size);

    /*
     *  Set entry point.
     */
    info->pc = (void *)li.entry;

    /*
     *  Build argument list on the new stack.
     */
    *cpp++ = (char *)argcount;
    cp2 = argbuf;
    for (i = 0; (unsigned long)i < argcount; i++) {
        *cpp++ = cp;
        strcpy(cp, cp2);
        cp += strlen(cp) + 1;
        cp2 += strlen(cp2) + 1;
    }
    free(argbuf);
    *cpp++ = NULL;   /* argv terminator */
    *cpp++ = NULL;   /* envp terminator */
    *cpp++ = 0;      /* aux vector terminator */

    /*
     *  Initialize registers.
     */
    for (i = 0; i < NUM_REGS; i++) {
        info->regs[i] = 0;
    }
    info->psr = 0;

    return (0);
}

/* ================================================================
 *  SetKernelBrk
 * ================================================================ */
int
SetKernelBrk(void *addr)
{
    unsigned long new_brk = (unsigned long)UP_TO_PAGE(addr);

    if (!vm_on) {
        /* Before VM: just track the break */
        kernel_brk_addr = (void *)new_brk;
        return 0;
    }

    /* After VM: allocate and map pages in Region 1 */
    int new_brk_page = new_brk >> PAGESHIFT;
    int old_brk_page = (unsigned long)kernel_brk_addr >> PAGESHIFT;

    if (new_brk_page > old_brk_page) {
        int vpn;
        for (vpn = old_brk_page; vpn < new_brk_page; vpn++) {
            int r1_vpn = vpn - (VMEM_1_BASE >> PAGESHIFT);
            if (r1_vpn < 0 || r1_vpn >= PAGE_TABLE_LEN) return -1;
            if (r1_pt[r1_vpn].valid) continue; /* Already mapped */

            int pfn = alloc_frame();
            if (pfn < 0) return -1;

            r1_pt[r1_vpn].valid = 1;
            r1_pt[r1_vpn].kprot = PROT_READ | PROT_WRITE;
            r1_pt[r1_vpn].uprot = PROT_NONE;
            r1_pt[r1_vpn].pfn = pfn;
            WriteRegister(REG_TLB_FLUSH,
                          (RCS421RegVal)((unsigned long)vpn << PAGESHIFT));
        }
    }
    /* Note: we don't shrink (per spec, kernel break never moves down) */

    kernel_brk_addr = (void *)new_brk;
    return 0;
}

/* ================================================================
 *  KernelStart
 * ================================================================ */
void
KernelStart(ExceptionInfo *info, unsigned int pmem_size,
            void *orig_brk, char **cmd_args)
{
    int i;
    TracePrintf(0, "KernelStart: pmem_size=%u orig_brk=%p\n",
                pmem_size, orig_brk);

    /* ---- Save initial kernel break ---- */
    kernel_brk_addr = (void *)UP_TO_PAGE(orig_brk);

    /* ---- Initialize interrupt vector table ---- */
    for (i = 0; i < TRAP_VECTOR_SIZE; i++) ivt[i] = NULL;
    ivt[TRAP_KERNEL]       = trap_kernel;
    ivt[TRAP_CLOCK]        = trap_clock;
    ivt[TRAP_ILLEGAL]      = trap_illegal;
    ivt[TRAP_MEMORY]       = trap_memory;
    ivt[TRAP_MATH]         = trap_math;
    ivt[TRAP_TTY_RECEIVE]  = trap_tty_recv;
    ivt[TRAP_TTY_TRANSMIT] = trap_tty_xmit;

    WriteRegister(REG_VECTOR_BASE, (RCS421RegVal)ivt);

    /* ---- Allocate frame_free array BEFORE enabling VM ---- */
    total_frames = pmem_size >> PAGESHIFT;
    frame_free = (int *)malloc(total_frames * sizeof(int));
    if (!frame_free) { TracePrintf(0, "malloc failed\n"); Halt(); }

    /* Re-snapshot kernel break (malloc may have moved it) */
    kernel_brk_addr = (void *)UP_TO_PAGE(kernel_brk_addr);

    /* ---- Build Region 1 page table ---- */
    memset(r1_pt, 0, sizeof(r1_pt));
    {
        unsigned long text_end = (unsigned long)&_etext;
        int text_top_vpn = (text_end - VMEM_1_BASE) >> PAGESHIFT;
        int brk_vpn = ((unsigned long)kernel_brk_addr - VMEM_1_BASE) >> PAGESHIFT;
        int r1_base_pfn = VMEM_1_BASE >> PAGESHIFT;

        /* Kernel text: read + exec, user read+exec (for idle) */
        for (i = 0; i < text_top_vpn; i++) {
            r1_pt[i].valid = 1;
            r1_pt[i].kprot = PROT_READ | PROT_EXEC;
            r1_pt[i].uprot = PROT_READ | PROT_EXEC;
            r1_pt[i].pfn = r1_base_pfn + i;
        }
        /* Kernel data/bss/heap: read + write */
        for (i = text_top_vpn; i < brk_vpn; i++) {
            r1_pt[i].valid = 1;
            r1_pt[i].kprot = PROT_READ | PROT_WRITE;
            r1_pt[i].uprot = PROT_NONE;
            r1_pt[i].pfn = r1_base_pfn + i;
        }
        kernel_brk_page = (unsigned long)kernel_brk_addr >> PAGESHIFT;
    }

    /* ---- Build initial Region 0 page table (kernel stack only) ---- */
    memset(boot_r0_pt, 0, sizeof(boot_r0_pt));
    {
        int ks_base = KERNEL_STACK_BASE >> PAGESHIFT;
        for (i = 0; i < KERNEL_STACK_PAGES; i++) {
            boot_r0_pt[ks_base + i].valid = 1;
            boot_r0_pt[ks_base + i].kprot = PROT_READ | PROT_WRITE;
            boot_r0_pt[ks_base + i].uprot = PROT_NONE;
            boot_r0_pt[ks_base + i].pfn = ks_base + i; /* Identity mapped */
        }
    }

    /* ---- Set page table registers and enable VM ---- */
    WriteRegister(REG_PTR0, (RCS421RegVal)boot_r0_pt);
    WriteRegister(REG_PTR1, (RCS421RegVal)r1_pt);
    WriteRegister(REG_VM_ENABLE, 1);
    vm_on = 1;

    TracePrintf(0, "KernelStart: VM enabled\n");

    /* ---- Initialize page table pool VPN counter ---- */
    pt_pool_next_vpn = TEMP_VPN - 1; /* Start just below temp page */

    /* ---- Build free frame list ---- */
    memset(frame_free, 0, total_frames * sizeof(int));
    for (i = 0; i < total_frames; i++) frame_free[i] = 1;
    num_free = total_frames;

    /* Mark kernel stack frames as used */
    {
        int ks_base = KERNEL_STACK_BASE >> PAGESHIFT;
        for (i = 0; i < KERNEL_STACK_PAGES; i++) {
            frame_free[ks_base + i] = 0;
            num_free--;
        }
    }

    /* Mark kernel text+data+heap frames as used */
    {
        int start = VMEM_1_BASE >> PAGESHIFT;
        int end = (unsigned long)kernel_brk_addr >> PAGESHIFT;
        for (i = start; i < end && i < total_frames; i++) {
            frame_free[i] = 0;
            num_free--;
        }
    }

    TracePrintf(0, "KernelStart: %d free frames out of %d total\n",
                num_free, total_frames);

    /* ---- Initialize TTY state ---- */
    for (i = 0; i < NUM_TERMINALS; i++) {
        tty_in_head[i] = tty_in_tail[i] = NULL;
        tty_rd_wait[i] = NULL;
        tty_wr_active[i] = NULL;
        tty_wr_head[i] = tty_wr_tail[i] = NULL;
    }

    /* ---- Create init process (pid 1) ---- */
    pcb_t *init_p = (pcb_t *)malloc(sizeof(pcb_t));
    if (!init_p) { TracePrintf(0, "malloc failed\n"); Halt(); }
    memset(init_p, 0, sizeof(pcb_t));
    init_p->pid = next_pid++; /* pid 0 - will become idle */

    /* Actually, idle = pid 0, init = pid 1. Let me fix ordering. */
    /* Create idle first with pid 0, then init with pid 1 */
    free(init_p); /* Redo */
    next_pid = 0;

    /* ---- Create idle process (pid 0) ---- */
    idle_proc = (pcb_t *)malloc(sizeof(pcb_t));
    if (!idle_proc) { TracePrintf(0, "malloc failed\n"); Halt(); }
    memset(idle_proc, 0, sizeof(pcb_t));
    idle_proc->pid = next_pid++; /* 0 */
    idle_proc->state = PROC_READY;

    unsigned long idle_pt_phys;
    idle_proc->pt = alloc_pt(&idle_pt_phys);
    if (!idle_proc->pt) { TracePrintf(0, "alloc_pt failed\n"); Halt(); }
    idle_proc->pt_phys = idle_pt_phys;

    /* Allocate kernel stack for idle */
    {
        int ks_base = KERNEL_STACK_BASE >> PAGESHIFT;
        for (i = 0; i < KERNEL_STACK_PAGES; i++) {
            int pfn = alloc_frame();
            if (pfn < 0) { TracePrintf(0, "alloc_frame failed\n"); Halt(); }
            idle_proc->pt[ks_base + i].valid = 1;
            idle_proc->pt[ks_base + i].kprot = PROT_READ | PROT_WRITE;
            idle_proc->pt[ks_base + i].uprot = PROT_NONE;
            idle_proc->pt[ks_base + i].pfn = pfn;
        }
    }

    /* Allocate one user stack page for idle */
    {
        int ustack_vpn = (USER_STACK_LIMIT >> PAGESHIFT) - 1;
        int pfn = alloc_frame();
        if (pfn < 0) { TracePrintf(0, "alloc_frame failed\n"); Halt(); }
        idle_proc->pt[ustack_vpn].valid = 1;
        idle_proc->pt[ustack_vpn].kprot = PROT_READ | PROT_WRITE;
        idle_proc->pt[ustack_vpn].uprot = PROT_READ | PROT_WRITE;
        idle_proc->pt[ustack_vpn].pfn = pfn;
        idle_proc->stack_base = ustack_vpn;
        idle_proc->brk_page = MEM_INVALID_PAGES;
    }

    /* ---- Create init process (pid 1) ---- */
    init_p = (pcb_t *)malloc(sizeof(pcb_t));
    if (!init_p) { TracePrintf(0, "malloc failed\n"); Halt(); }
    memset(init_p, 0, sizeof(pcb_t));
    init_p->pid = next_pid++; /* 1 */
    init_p->state = PROC_RUNNING;

    /* Allocate a proper page table for init */
    unsigned long init_pt_phys;
    init_p->pt = alloc_pt(&init_pt_phys);
    if (!init_p->pt) { TracePrintf(0, "alloc_pt failed\n"); Halt(); }
    init_p->pt_phys = init_pt_phys;

    /* Copy kernel stack entries from boot page table */
    {
        int ks_base = KERNEL_STACK_BASE >> PAGESHIFT;
        for (i = 0; i < KERNEL_STACK_PAGES; i++) {
            init_p->pt[ks_base + i] = boot_r0_pt[ks_base + i];
        }
    }

    /* Switch to init's page table */
    WriteRegister(REG_PTR0, (RCS421RegVal)init_pt_phys);
    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);

    init_p->brk_page = MEM_INVALID_PAGES;
    init_p->stack_base = (USER_STACK_LIMIT >> PAGESHIFT) - 1;
    cur_proc = init_p;
    num_procs = 1;

    /* ---- Initialize idle's context via ContextSwitch ---- */
    TracePrintf(0, "KernelStart: Creating idle context\n");
    ContextSwitch(copy_switch, &idle_proc->ctx, idle_proc, NULL);

    /* Both init and idle will resume here (eventually).
     * When idle is context-switched to later, cur_proc == idle_proc. */
    if (cur_proc == idle_proc) {
        TracePrintf(0, "Idle process starting\n");
        do_idle(); /* Never returns */
    }

    /* We are still init. Load the init program. */
    char *init_name = NULL;
    if (cmd_args && cmd_args[0]) {
        init_name = cmd_args[0];
    }
    if (!init_name) {
        TracePrintf(0, "KernelStart: No init program specified. Halting.\n");
        Halt();
    }

    TracePrintf(0, "KernelStart: Loading init program '%s'\n", init_name);
    int rc = load_program(init_name, cmd_args, info, init_p);
    if (rc < 0) {
        TracePrintf(0, "KernelStart: LoadProgram failed (%d). Halting.\n", rc);
        Halt();
    }

    TracePrintf(0, "KernelStart: Init loaded, returning to user mode\n");
    /* info has been set up by load_program: pc, sp, regs, psr */
}

