183→static unsigned long v2p(void *vaddr) {
184→    unsigned long a = (unsigned long)vaddr;
185→    int vpn, offset;
186→    if (a >= VMEM_1_BASE && a < VMEM_1_LIMIT) {
187→        vpn = (a - VMEM_1_BASE) >> PAGESHIFT;
188→        offset = a & PAGEOFFSET;
189→        return ((unsigned long)r1_pt[vpn].pfn << PAGESHIFT) | offset;
190→    }
