194→/* ================================================================
195→ *  Page Table Allocation (from physical frames, mapped in R1)
196→ * ================================================================ */
197→static struct pte *alloc_pt(unsigned long *phys_out) {
198→    int pfn = alloc_frame();
199→    if (pfn < 0) return NULL;
200→
201→    int vpn = pt_pool_next_vpn--;
202→    if (vpn <= 0) {
203→        free_frame(pfn);
204→        pt_pool_next_vpn++;
205→        return NULL;
206→    }
207→
208→    r1_pt[vpn].valid = 1;
209→    r1_pt[vpn].kprot = PROT_READ | PROT_WRITE;
210→    r1_pt[vpn].uprot = PROT_NONE;
211→    r1_pt[vpn].pfn = pfn;
212→    WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)(VMEM_1_BASE + vpn * PAGESIZE));
213→
214→    struct pte *pt = (struct pte *)(VMEM_1_BASE + vpn * PAGESIZE);
215→    memset(pt, 0, PAGE_TABLE_SIZE);
216→    *phys_out = (unsigned long)pfn << PAGESHIFT;
217→    return pt;
218→}
