374→static void schedule(ExceptionInfo *info) {
375→    (void)info;
376→    reap_dead();
377→
378→    pcb_t *next = dequeue_ready();
379→    if (!next) next = idle_proc;
380→    if (next == cur_proc) return;
381→
382→    pcb_t *old = cur_proc;
383→    next->state = PROC_RUNNING;
384→    next->clock_ticks = 0;
