391→/* ================================================================
392→ *  Process Termination
393→ * ================================================================ */
394→static void remove_child(pcb_t *parent, pcb_t *child) {
395→    pcb_t **pp = &parent->children;
396→    while (*pp && *pp != child) pp = &(*pp)->sibling;
397→    if (*pp == child) *pp = child->sibling;
398→    child->sibling = NULL;
