401→static void terminate(pcb_t *proc, int status, ExceptionInfo *info) {
402→    TracePrintf(1, "Terminate pid %d status %d\n", proc->pid, status);
403→    int i;
404→
405→    /* Free user pages (not kernel stack) */
406→    int ks_base = KERNEL_STACK_BASE >> PAGESHIFT;
407→    for (i = 0; i < ks_base; i++) {
408→        if (proc->pt[i].valid) {
409→            free_frame(proc->pt[i].pfn);
410→            proc->pt[i].valid = 0;
411→        }
412→    }
413→
414→    /* Orphan all children */
415→    pcb_t *ch = proc->children;
416→    while (ch) {
417→        pcb_t *nxt = ch->sibling;
418→        ch->parent = NULL;
419→        ch->sibling = NULL;
420→        ch = nxt;
421→    }
422→    proc->children = NULL;
423→
424→    /* Free zombie children (they'll never be collected) */
425→    pcb_t *z = proc->zombie_children;
426→    while (z) {
427→        pcb_t *nxt = z->zombie_next;
428→        free_zombie(z);
429→        z = nxt;
430→    }
431→    proc->zombie_children = NULL;
432→
433→    /* Notify parent */
434→    if (proc->parent) {
435→        pcb_t *par = proc->parent;
436→        remove_child(par, proc);
437→
438→        if (par->is_waiting) {
439→            /* Wake parent */
440→            par->wait_child_pid = proc->pid;
441→            par->wait_child_status = status;
442→            par->is_waiting = 0;
443→            enqueue_ready(par);
444→            /* Defer cleanup of proc */
445→            proc->state = PROC_DEAD;
446→            proc->next = reap_list;
447→            reap_list = proc;
448→        } else {
449→            /* Become zombie */

450→            proc->state = PROC_ZOMBIE;
451→            proc->exit_status = status;
452→            proc->zombie_next = par->zombie_children;
453→            par->zombie_children = proc;
454→        }
455→    } else {
456→        /* Orphan - defer cleanup */
457→        proc->state = PROC_DEAD;
458→        proc->next = reap_list;
459→        reap_list = proc;
460→    }
461→
462→    num_procs--;
463→    if (num_procs <= 0) {
464→        TracePrintf(0, "All user processes exited. Halting.\n");
465→        Halt();
466→    }
467→
468→    /* Must switch away from this process */
469→    pcb_t *next = dequeue_ready();
470→    if (!next) next = idle_proc;
471→
472→    pcb_t *old = cur_proc;
473→    next->state = PROC_RUNNING;
474→    next->clock_ticks = 0;
475→    ContextSwitch(switch_func, &old->ctx, old, next);
476→    reap_dead();
477→}
