488→/* ================================================================
489→ *  Trap Handlers
490→ * ================================================================ */
491→static void trap_kernel(ExceptionInfo *info) {
492→    int code = info->code;
493→    int result;
494→
495→    switch (code) {
496→    case YALNIX_FORK:
497→        result = kern_fork(info);
498→        info->regs[0] = result;
499→        break;
500→    case YALNIX_EXEC:
501→        result = kern_exec((char *)info->regs[1], (char **)info->regs[2], info);
502→        info->regs[0] = result;
503→        break;
504→    case YALNIX_EXIT:
505→        kern_exit((int)info->regs[1], info);
506→        /* Should not return for the exiting process */
507→        break;
508→    case YALNIX_WAIT:
509→        result = kern_wait((int *)info->regs[1], info);
510→        info->regs[0] = result;
511→        break;
512→    case YALNIX_GETPID:
513→        info->regs[0] = cur_proc->pid;
514→        break;
515→    case YALNIX_BRK:
516→        result = kern_brk((void *)info->regs[1]);
517→        info->regs[0] = result;
518→        break;
519→    case YALNIX_DELAY:
520→        result = kern_delay((int)info->regs[1], info);
521→        info->regs[0] = result;
522→        break;
523→    case YALNIX_TTY_READ:
524→        result = kern_ttyread((int)info->regs[1], (void *)info->regs[2],
525→                              (int)info->regs[3], info);
526→        info->regs[0] = result;
527→        break;
528→    case YALNIX_TTY_WRITE:
529→        result = kern_ttywrite((int)info->regs[1], (void *)info->regs[2],
530→                               (int)info->regs[3], info);
531→        info->regs[0] = result;
532→        break;
533→    default:
534→        TracePrintf(0, "Unknown syscall %d from pid %d\n", code, cur_proc->pid);
535→        info->regs[0] = ERROR;
536→        break;
537→    }
538→}
