540→static void trap_clock(ExceptionInfo *info) {
541→    /* Decrement delay counters */
542→    pcb_t **pp = &delay_q;
543→    while (*pp) {
544→        (*pp)->delay_remaining--;
545→        if ((*pp)->delay_remaining <= 0) {
546→            pcb_t *wake = *pp;
547→            *pp = wake->next;
548→            wake->next = NULL;
549→            enqueue_ready(wake);
550→        } else {
551→            pp = &(*pp)->next;
552→        }
553→    }
554→
555→    /* Round-robin scheduling */
556→    if (cur_proc != idle_proc) {
557→        cur_proc->clock_ticks++;
558→        if (cur_proc->clock_ticks >= CLOCK_QUANTUM && rq_head) {
559→            enqueue_ready(cur_proc);
560→            schedule(info);
561→        }
562→    } else {
563→        /* Idle: switch to any ready process */
564→        if (rq_head) {
565→            schedule(info);
566→        }
567→    }
568→}
