570→static void trap_illegal(ExceptionInfo *info) {
571→    TracePrintf(0, "TRAP_ILLEGAL: pid %d, code %d, pc %p\n",
572→                cur_proc->pid, info->code, info->pc);
573→    if (cur_proc == idle_proc) { Halt(); }
574→    terminate(cur_proc, ERROR, info);
575→}
