577→static void trap_memory(ExceptionInfo *info) {
578→    unsigned long addr = (unsigned long)info->addr;
579→    int fault_vpn = addr >> PAGESHIFT;
580→    int ks_base = KERNEL_STACK_BASE >> PAGESHIFT;
581→
582→    /* Check if this is a stack growth request */
583→    if (addr >= MEM_INVALID_SIZE && addr < (unsigned long)USER_STACK_LIMIT &&
584→        fault_vpn >= cur_proc->brk_page + 1 &&  /* Red zone */
585→        fault_vpn < (USER_STACK_LIMIT >> PAGESHIFT)) {
586→
587→        /* Grow stack down to fault_vpn */
588→        int i;
589→        for (i = fault_vpn; i < cur_proc->stack_base; i++) {
590→            if (cur_proc->pt[i].valid) continue;
591→            int pfn = alloc_frame();
592→            if (pfn < 0) goto kill;
593→            cur_proc->pt[i].valid = 1;
594→            cur_proc->pt[i].kprot = PROT_READ | PROT_WRITE;
595→            cur_proc->pt[i].uprot = PROT_READ | PROT_WRITE;
596→            cur_proc->pt[i].pfn = pfn;
597→        }
598→        cur_proc->stack_base = fault_vpn;
599→        WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
600→        return;
601→    }
602→
603→kill:
604→    TracePrintf(0, "TRAP_MEMORY: pid %d, addr %p, code %d\n",
605→                cur_proc->pid, info->addr, info->code);
606→    if (cur_proc == idle_proc) { Halt(); }
607→    terminate(cur_proc, ERROR, info);
608→}
