616→static void trap_tty_recv(ExceptionInfo *info) {
617→    int tty = info->code;
618→    if (tty < 0 || tty >= NUM_TERMINALS) return;
619→
620→    /* Read from hardware into a new buffer */
621→    tty_line_t *line = (tty_line_t *)malloc(sizeof(tty_line_t));
622→    if (!line) return;
623→    line->len = TtyReceive(tty, line->data, TERMINAL_MAX_LINE);
624→    line->next = NULL;
625→
626→    /* Append to input queue */
627→    if (!tty_in_tail[tty]) {
628→        tty_in_head[tty] = tty_in_tail[tty] = line;
629→    } else {
630→        tty_in_tail[tty]->next = line;
631→        tty_in_tail[tty] = line;
632→    }
633→
634→    /* Wake blocked reader if any */
635→    if (tty_rd_wait[tty]) {
636→        pcb_t *reader = tty_rd_wait[tty];
637→        tty_rd_wait[tty] = reader->next;
638→        reader->next = NULL;
639→        enqueue_ready(reader);
640→    }
641→}
642→
643→static void trap_tty_xmit(ExceptionInfo *info) {
644→    int tty = info->code;
645→    if (tty < 0 || tty >= NUM_TERMINALS) return;
646→
647→    /* Current transmit is done; unblock the writer */
648→    pcb_t *writer = tty_wr_active[tty];
649→    tty_wr_active[tty] = NULL;

650→    if (writer) {
651→        writer->tty_wr_active[tty] = NULL; /* Not a real field, see below */
652→        enqueue_ready(writer);
653→    }
654→
655→    /* Start next pending write if any */
656→    if (tty_wr_head[tty]) {
657→        pcb_t *nw = tty_wr_head[tty];
658→        tty_wr_head[tty] = nw->next;
659→        if (!tty_wr_head[tty]) tty_wr_tail[tty] = NULL;
660→        nw->next = NULL;
661→        tty_wr_active[tty] = nw;
662→        /* Copy from saved data and transmit */
663→        /* The data was already copied to tty_kbuf when TtyWrite was called */
664→        TtyTransmit(tty, tty_kbuf[tty], nw->exit_status); /* Reusing exit_status for len */
665→    }
666→}
