672→static int kern_fork(ExceptionInfo *info) {
673→    int i;
674→    int ks_base = KERNEL_STACK_BASE >> PAGESHIFT;
675→
676→    /* Count how many pages the child needs */
677→    int pages_needed = KERNEL_STACK_PAGES;
678→    for (i = 0; i < ks_base; i++) {
679→        if (cur_proc->pt[i].valid) pages_needed++;
680→    }
681→    if (pages_needed > num_free) return ERROR;
682→
683→    /* Allocate child PCB */
684→    pcb_t *child = (pcb_t *)malloc(sizeof(pcb_t));
685→    if (!child) return ERROR;
686→    memset(child, 0, sizeof(pcb_t));
687→    child->pid = next_pid++;
688→    child->state = PROC_READY;
689→    child->brk_page = cur_proc->brk_page;
690→    child->stack_base = cur_proc->stack_base;
691→    child->parent = cur_proc;
692→
693→    /* Allocate page table */
694→    unsigned long child_pt_phys;
695→    child->pt = alloc_pt(&child_pt_phys);
696→    if (!child->pt) {
697→        free(child);
698→        return ERROR;
699→    }
700→    child->pt_phys = child_pt_phys;
701→
702→    /* Allocate kernel stack pages for child */
703→    for (i = 0; i < KERNEL_STACK_PAGES; i++) {
704→        int pfn = alloc_frame();
705→        if (pfn < 0) {
706→            /* Cleanup */
707→            int j;
708→            for (j = 0; j < i; j++)
709→                free_frame(child->pt[ks_base + j].pfn);
710→            free_pt(child->pt);
711→            free(child);
712→            return ERROR;
713→        }
714→        child->pt[ks_base + i].valid = 1;
715→        child->pt[ks_base + i].kprot = PROT_READ | PROT_WRITE;
716→        child->pt[ks_base + i].uprot = PROT_NONE;
717→        child->pt[ks_base + i].pfn = pfn;
718→    }
719→
720→    /* Copy user pages from parent to child */
721→    for (i = 0; i < ks_base; i++) {
722→        if (!cur_proc->pt[i].valid) continue;
723→        int pfn = alloc_frame();
724→        if (pfn < 0) {
725→            /* Cleanup: free all child pages allocated so far */
726→            int j;
727→            for (j = 0; j < ks_base; j++) {
728→                if (child->pt[j].valid) free_frame(child->pt[j].pfn);
729→            }
730→            for (j = 0; j < KERNEL_STACK_PAGES; j++)
731→                free_frame(child->pt[ks_base + j].pfn);
732→            free_pt(child->pt);
733→            free(child);
734→            return ERROR;
735→        }
736→        child->pt[i] = cur_proc->pt[i];
737→        child->pt[i].pfn = pfn;
738→
739→        /* Copy page via temp mapping */
740→        r1_pt[TEMP_VPN].valid = 1;
741→        r1_pt[TEMP_VPN].kprot = PROT_READ | PROT_WRITE;
742→        r1_pt[TEMP_VPN].uprot = PROT_NONE;
743→        r1_pt[TEMP_VPN].pfn = pfn;
744→        WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)TEMP_VADDR);
745→        memcpy((void *)TEMP_VADDR, (void *)((unsigned long)i << PAGESHIFT), PAGESIZE);
746→    }
747→    r1_pt[TEMP_VPN].valid = 0;
748→    WriteRegister(REG_TLB_FLUSH, (RCS421RegVal)TEMP_VADDR);
749→
750→    /* Link child to parent */
751→    child->sibling = cur_proc->children;
752→    cur_proc->children = child;
753→    num_procs++;
754→
755→    /* Copy kernel stack and create SavedContext for child */
756→    ContextSwitch(fork_switch, &cur_proc->ctx, cur_proc, child);
757→
758→    /* Both parent and child resume here */
759→    if (cur_proc->pid == child->pid) {
760→        /* We are the child */
761→        return 0;
762→    }
763→
764→    /* We are the parent */
765→    enqueue_ready(child);
766→    return child->pid;
767→}
