769→static int kern_exec(char *name, char **argv, ExceptionInfo *info) {
770→    if (!check_str(name)) return ERROR;
771→
772→    /* Validate argv array */
773→    unsigned long argv_addr = (unsigned long)argv;
774→    if (argv_addr < MEM_INVALID_SIZE) return ERROR;
775→    int argc = 0;
776→    while (1) {
777→        if (!check_buf(&argv[argc], sizeof(char *), 0)) return ERROR;
778→        if (argv[argc] == NULL) break;
779→        if (!check_str(argv[argc])) return ERROR;
780→        argc++;
781→    }
782→
783→    int rc = load_program(name, argv, info, cur_proc);
784→    if (rc < 0) {
785→        if (rc == -2) {
786→            /* Process is no longer runnable */
787→            terminate(cur_proc, ERROR, info);
788→            return ERROR; /* Not reached */
789→        }
790→        return ERROR;
791→    }
792→    /* On success, load_program sets up info for the new program.
793→     * When trap handler returns, the new program starts. */
794→    return 0; /* Not actually used - new program starts fresh */
795→}
