797→static void kern_exit(int status, ExceptionInfo *info) {
798→    if (cur_proc == idle_proc) {
799→        TracePrintf(0, "Idle tried to exit. Halting.\n");
800→        Halt();
801→    }
802→    terminate(cur_proc, status, info);
803→}
