805→static int kern_wait(int *status_ptr, ExceptionInfo *info) {
806→    /* Validate status_ptr */
807→    if (!check_buf(status_ptr, sizeof(int), 1)) return ERROR;
808→
809→    /* Check for zombie children */
810→    if (cur_proc->zombie_children) {
811→        pcb_t *z = cur_proc->zombie_children;
812→        cur_proc->zombie_children = z->zombie_next;
813→        int pid = z->pid;
814→        *status_ptr = z->exit_status;
815→        free_zombie(z);
816→        return pid;
817→    }
818→
819→    /* Any living children? */
820→    if (!cur_proc->children) return ERROR;
821→
822→    /* Block until a child exits */
823→    cur_proc->state = PROC_BLOCKED;
824→    cur_proc->is_waiting = 1;
825→    schedule(info);
826→
827→    /* Woken up by child exit */
828→    *status_ptr = cur_proc->wait_child_status;
829→    return cur_proc->wait_child_pid;
830→}
