832→static int kern_brk(void *addr) {
833→    unsigned long new_brk = (unsigned long)UP_TO_PAGE(addr);
834→    int new_brk_page = new_brk >> PAGESHIFT;
835→    int i;
836→
837→    if (new_brk_page < MEM_INVALID_PAGES) return ERROR;
838→    /* Must leave red zone between heap and stack */
839→    if (new_brk_page >= cur_proc->stack_base) return ERROR;
840→
841→    if (new_brk_page > cur_proc->brk_page) {
842→        /* Growing */
843→        int needed = new_brk_page - cur_proc->brk_page;
844→        if (needed > num_free) return ERROR;
845→        for (i = cur_proc->brk_page; i < new_brk_page; i++) {
846→            int pfn = alloc_frame();
847→            if (pfn < 0) return ERROR;
848→            cur_proc->pt[i].valid = 1;
849→            cur_proc->pt[i].kprot = PROT_READ | PROT_WRITE;

 850→            cur_proc->pt[i].uprot = PROT_READ | PROT_WRITE;
 851→            cur_proc->pt[i].pfn = pfn;
 852→        }
 853→    } else if (new_brk_page < cur_proc->brk_page) {
 854→        /* Shrinking */
 855→        for (i = new_brk_page; i < cur_proc->brk_page; i++) {
 856→            if (cur_proc->pt[i].valid) {
 857→                free_frame(cur_proc->pt[i].pfn);
 858→                cur_proc->pt[i].valid = 0;
 859→            }
 860→        }
 861→    }
 862→    cur_proc->brk_page = new_brk_page;
 863→    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
 864→    return 0;
 865→}
