 867→static int kern_delay(int ticks, ExceptionInfo *info) {
 868→    if (ticks < 0) return ERROR;
 869→    if (ticks == 0) return 0;
 870→
 871→    cur_proc->delay_remaining = ticks;
 872→    cur_proc->state = PROC_BLOCKED;
 873→    cur_proc->next = delay_q;
 874→    delay_q = cur_proc;
 875→
 876→    schedule(info);
 877→    return 0;
 878→}
