 880→static int kern_ttyread(int tty_id, void *buf, int len, ExceptionInfo *info) {
 881→    if (tty_id < 0 || tty_id >= NUM_TERMINALS) return ERROR;
 882→    if (len < 0) return ERROR;
 883→    if (len == 0) return 0;
 884→    if (!check_buf(buf, len, 1)) return ERROR;
 885→
 886→    /* Wait for input if none available */
 887→    while (!tty_in_head[tty_id]) {
 888→        cur_proc->state = PROC_BLOCKED;
 889→        cur_proc->next = tty_rd_wait[tty_id];
 890→        tty_rd_wait[tty_id] = cur_proc;
 891→        schedule(info);
 892→    }
 893→
 894→    /* Copy from input buffer */
 895→    tty_line_t *line = tty_in_head[tty_id];
 896→    int to_copy = (len < line->len) ? len : line->len;
 897→    memcpy(buf, line->data, to_copy);
 898→
 899→    if (to_copy < line->len) {
 900→        /* Partial read: shift remaining data */
 901→        memmove(line->data, line->data + to_copy, line->len - to_copy);
 902→        line->len -= to_copy;
 903→    } else {
 904→        /* Consumed entire line */
 905→        tty_in_head[tty_id] = line->next;
 906→        if (!tty_in_head[tty_id]) tty_in_tail[tty_id] = NULL;
 907→        free(line);
 908→    }
 909→    return to_copy;
 910→}
 911→
 912→static int kern_ttywrite(int tty_id, void *buf, int len, ExceptionInfo *info) {
 913→    if (tty_id < 0 || tty_id >= NUM_TERMINALS) return ERROR;
 914→    if (len < 0 || len > TERMINAL_MAX_LINE) return ERROR;
 915→    if (len == 0) return 0;
 916→    if (!check_buf(buf, len, 0)) return ERROR;
 917→
 918→    /* Copy user data to kernel buffer */
 919→    memcpy(tty_kbuf[tty_id], buf, len);
 920→    int orig_len = len;
 921→
 922→    if (!tty_wr_active[tty_id]) {
 923→        /* Terminal is free; start transmitting */
 924→        tty_wr_active[tty_id] = cur_proc;
 925→        cur_proc->exit_status = len; /* Stash len for transmit handler */
 926→        TtyTransmit(tty_id, tty_kbuf[tty_id], len);
 927→    } else {
 928→        /* Queue this write */
 929→        cur_proc->exit_status = len;
 930→        cur_proc->next = NULL;
 931→        if (!tty_wr_tail[tty_id]) {
 932→            tty_wr_head[tty_id] = tty_wr_tail[tty_id] = cur_proc;
 933→        } else {
 934→            tty_wr_tail[tty_id]->next = cur_proc;
 935→            tty_wr_tail[tty_id] = cur_proc;
 936→        }
 937→    }
 938→
 939→    /* Block until transmit completes */
 940→    cur_proc->state = PROC_BLOCKED;
 941→    schedule(info);
 942→
 943→    return orig_len;
 944→}
