 946→/* ================================================================
 947→ *  LoadProgram (adapted from load.template)
 948→ * ================================================================ */
 949→static int
 950→load_program(char *name, char **args, ExceptionInfo *info, pcb_t *proc)
 951→{
 952→    int fd;
 953→    int status;
 954→    struct loadinfo li;
 955→    char *cp;
 956→    char *cp2;
 957→    char **cpp;
 958→    char *argbuf;
 959→    int i;
 960→    unsigned long argcount;
 961→    int size;
 962→    int text_npg;
 963→    int data_bss_npg;
 964→    int stack_npg;
 965→
 966→    TracePrintf(1, "LoadProgram '%s', args %p\n", name, args);
 967→
 968→    if ((fd = open(name, O_RDONLY)) < 0) {
 969→        TracePrintf(0, "LoadProgram: can't open file '%s'\n", name);
 970→        return (-1);
 971→    }
 972→
 973→    status = LoadInfo(fd, &li);
 974→    TracePrintf(1, "LoadProgram: LoadInfo status %d\n", status);
 975→    switch (status) {
 976→    case LI_SUCCESS:
 977→        break;
 978→    case LI_FORMAT_ERROR:
 979→        TracePrintf(0, "LoadProgram: '%s' not in Yalnix format\n", name);
 980→        close(fd);
 981→        return (-1);
 982→    case LI_OTHER_ERROR:
 983→        TracePrintf(0, "LoadProgram: '%s' other error\n", name);
 984→        close(fd);
 985→        return (-1);
 986→    default:
 987→        TracePrintf(0, "LoadProgram: '%s' unknown error\n", name);
 988→        close(fd);
 989→        return (-1);
 990→    }
 991→    TracePrintf(1, "text_size 0x%lx, data_size 0x%lx, bss_size 0x%lx\n",
 992→                li.text_size, li.data_size, li.bss_size);
 993→    TracePrintf(1, "entry 0x%lx\n", li.entry);
 994→
 995→    /*
 996→     *  Figure out how many bytes for arguments on new stack.
 997→     */
 998→    size = 0;
 999→    for (i = 0; args[i] != NULL; i++) {
1000→        size += strlen(args[i]) + 1;
1001→    }
1002→    argcount = i;
1003→    TracePrintf(1, "LoadProgram: size %d, argcount %d\n", size, (int)argcount);
1004→
1005→    /*
1006→     *  Save arguments in Region 1 buffer.
1007→     */
1008→    cp = argbuf = (char *)malloc(size);
1009→    if (!argbuf) { close(fd); return (-1); }
1010→    for (i = 0; args[i] != NULL; i++) {
1011→        strcpy(cp, args[i]);
1012→        cp += strlen(cp) + 1;
1013→    }
1014→
1015→    /*
1016→     *  Compute stack layout.
1017→     */
1018→    cp = ((char *)USER_STACK_LIMIT) - size;
1019→    cpp = (char **)((unsigned long)cp & (-1 << 4));   /* align cpp */
1020→    cpp = (char **)((unsigned long)cpp - ((argcount + 4) * sizeof(void *)));
1021→
1022→    text_npg = li.text_size >> PAGESHIFT;
1023→    data_bss_npg = UP_TO_PAGE(li.data_size + li.bss_size) >> PAGESHIFT;
1024→    stack_npg = (USER_STACK_LIMIT - DOWN_TO_PAGE(cpp)) >> PAGESHIFT;
1025→
1026→    TracePrintf(1, "LoadProgram: text_npg %d, data_bss_npg %d, stack_npg %d\n",
1027→                text_npg, data_bss_npg, stack_npg);
1028→
1029→    /*
1030→     *  Check virtual memory size.
1031→     */
1032→    if (MEM_INVALID_PAGES + text_npg + data_bss_npg + 1 + stack_npg +
1033→        1 + KERNEL_STACK_PAGES > PAGE_TABLE_LEN) {
1034→        TracePrintf(0, "LoadProgram: '%s' too large for VIRTUAL memory\n", name);
1035→        free(argbuf);
1036→        close(fd);
1037→        return (-1);
1038→    }
1039→
1040→    /*
1041→     *  Check physical memory (accounting for pages that will be freed).
1042→     */
1043→    {
1044→        int pages_needed = text_npg + data_bss_npg + stack_npg;
1045→        int pages_to_free = 0;
1046→        int ks_base_vpn = KERNEL_STACK_BASE >> PAGESHIFT;
1047→        for (i = 0; i < ks_base_vpn; i++) {
1048→            if (proc->pt[i].valid) pages_to_free++;
1049→        }

  1050→        if (pages_needed - pages_to_free > num_free) {
  1051→            TracePrintf(0, "LoadProgram: '%s' too large for PHYSICAL memory\n", name);
  1052→            free(argbuf);
  1053→            close(fd);
  1054→            return (-1);
  1055→        }
  1056→    }
  1057→
  1058→    /* Initialize sp */
  1059→    info->sp = (void *)cpp;
  1060→
  1061→    /*
  1062→     *  Free old Region 0 pages (except kernel stack).
  1063→     */
  1064→    {
  1065→        int ks_base_vpn = KERNEL_STACK_BASE >> PAGESHIFT;
  1066→        for (i = 0; i < ks_base_vpn; i++) {
  1067→            if (proc->pt[i].valid) {
  1068→                free_frame(proc->pt[i].pfn);
  1069→                proc->pt[i].valid = 0;
  1070→            }
  1071→        }
  1072→    }
  1073→
  1074→    /*
  1075→     *  Set up text, data+bss, stack pages.
  1076→     */
  1077→    {
  1078→        int vpn = MEM_INVALID_PAGES;
  1079→
  1080→        /* Text pages */
  1081→        for (i = 0; i < text_npg; i++) {
  1082→            int pfn = alloc_frame();
  1083→            proc->pt[vpn].valid = 1;
  1084→            proc->pt[vpn].kprot = PROT_READ | PROT_WRITE;
  1085→            proc->pt[vpn].uprot = PROT_READ | PROT_EXEC;
  1086→            proc->pt[vpn].pfn = pfn;
  1087→            vpn++;
  1088→        }
  1089→
  1090→        /* Data + BSS pages */
  1091→        for (i = 0; i < data_bss_npg; i++) {
  1092→            int pfn = alloc_frame();
  1093→            proc->pt[vpn].valid = 1;
  1094→            proc->pt[vpn].kprot = PROT_READ | PROT_WRITE;
  1095→            proc->pt[vpn].uprot = PROT_READ | PROT_WRITE;
  1096→            proc->pt[vpn].pfn = pfn;
  1097→            vpn++;
  1098→        }
  1099→
  1100→        /* Update brk for this process */
  1101→        proc->brk_page = vpn;
  1102→
  1103→        /* Stack pages (at top of Region 0 user area) */
  1104→        int stack_top_vpn = (USER_STACK_LIMIT >> PAGESHIFT) - 1;
  1105→        for (i = 0; i < stack_npg; i++) {
  1106→            int sv = stack_top_vpn - stack_npg + 1 + i;
  1107→            int pfn = alloc_frame();
  1108→            proc->pt[sv].valid = 1;
  1109→            proc->pt[sv].kprot = PROT_READ | PROT_WRITE;
  1110→            proc->pt[sv].uprot = PROT_READ | PROT_WRITE;
  1111→            proc->pt[sv].pfn = pfn;
  1112→        }
  1113→        proc->stack_base = stack_top_vpn - stack_npg + 1;
  1114→    }
  1115→
  1116→    /* Flush TLB for Region 0 */
  1117→    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
  1118→
  1119→    /*
  1120→     *  Read text and data from file.
  1121→     */
  1122→    if (read(fd, (void *)MEM_INVALID_SIZE, li.text_size + li.data_size)
  1123→        != (ssize_t)(li.text_size + li.data_size)) {
  1124→        TracePrintf(0, "LoadProgram: couldn't read for '%s'\n", name);
  1125→        free(argbuf);
  1126→        close(fd);
  1127→        return (-2);
  1128→    }
  1129→
  1130→    close(fd);
  1131→
  1132→    /*
  1133→     *  Set text pages to read/exec (was read/write for loading).
  1134→     */
  1135→    {
  1136→        int vpn = MEM_INVALID_PAGES;
  1137→        for (i = 0; i < text_npg; i++) {
  1138→            proc->pt[vpn + i].kprot = PROT_READ | PROT_EXEC;
  1139→        }
  1140→    }
  1141→    WriteRegister(REG_TLB_FLUSH, TLB_FLUSH_0);
  1142→
  1143→    /*
  1144→     *  Zero out BSS.
  1145→     */
  1146→    memset((void *)(MEM_INVALID_SIZE + li.text_size + li.data_size),
  1147→           '\0', li.bss_size);
  1148→
  1149→    /*
